public static SalesTable createSalesTable(SalesAgreementHeader _salesAgreementHeader,PurchId _purchId)
{        
    ETG_SalesAgreementHeader    salesAgreementHeaderTrade;
    SalesAgreementHeaderHistory agreementHeaderHistory;
    SalesTable                  salesTable;
    NumberSeq                   numberSeq;

    try
    {
        select firstonly ConfirmationNumber,SalesNumberSequence from agreementHeaderHistory
            order by agreementHeaderHistory.ConfirmationNumber desc
                where agreementHeaderHistory.SalesNumberSequence == _salesAgreementHeader.SalesNumberSequence
        join salesAgreementHeaderTrade
            where salesAgreementHeaderTrade.SalesAgreementId == agreementHeaderHistory.SalesNumberSequence;

        salesTable.clear();
        numberSeq = NumberSeq::newGetNum(SalesParameters::numRefSalesId());
        numberSeq.used();
        salesTable.SalesId = numberSeq.num();          
        salesTable.initValue();

        salesTable.CustAccount = _salesAgreementHeader.CustAccount;
        salesTable.initFromCustTable();
        salesTable.initFromSalesAgreementHeader(_salesAgreementHeader,true);
        salesTable.ETG_TPPurchId                  = _purchId;
        salesTable.ETG_IsThirdParty               = NoYes::Yes;
        salesTable.ETG_SalesAgreementIdComfirmVer = _salesAgreementHeader.SalesNumberSequence + "-" + agreementHeaderHistory.ConfirmationNumber;
        salesTable.DefaultDimension = _salesAgreementHeader.DefaultDimension;

        salesTable.insert();

        if (salesTable.DefaultDimension != _salesAgreementHeader.DefaultDimension)
        {
            ttsbegin;
            salesTable.selectForUpdate(true);
            salesTable.DefaultDimension = _salesAgreementHeader.DefaultDimension;
            salesTable.doUpdate();
            ttscommit;
        }

        info(strFmt('TP sales order %1 has been created successfully',salesTable.SalesId));
        ETG_ReleaseOrder::createSalesTrade(salesTable.SalesId,salesAgreementHeaderTrade);
        if(salesTable.InterCompanyPurchId)
        {
            ETG_ReleaseOrder::intercompanyPurchTrade(salesTable);
        }

    }
    catch(Exception::Error)
    {
        ttsabort;
    }

    return salesTable;
}

