public static SalesLine createSalesLine(AgreementLineQuantityCommitment _agreementLine,PurchLine _purchLine)
{
    SalesLine               salesLine;
    SalesTable              salesTable = SalesTable::find(_purchLine.purchTable().ETG_TPSalesId);

    salesLine.SalesId       = salesTable.SalesId;
    salesLine.initFromSalesTable(salesTable);
    salesLine.ItemId            = _agreementLine.ItemId;
    salesLine.initFromItemOrCategory(salesLine.ItemId,0,'',false);       
    salesLine.initFromAgreementLine(_agreementLine);
    salesLine.SalesQty              = _purchLine.PurchQty;
    salesLine.QtyOrdered            = salesLine.calcQtyOrdered(salesLine.SalesQty);
    salesLine.ETG_TPInventTransId   = _purchLine.InventTransId;
    salesLine.MatchingAgreementLine = _agreementLine.RecId;

    if(ETG_Parameters::find().ETGIsAutoMarking)

    {
        salesLine.InventRefTransId        = _purchLine.InventTransId;
        salesLine.InventRefId             = _purchLine.PurchId;
    }
    salesLine.DefaultDimension = _agreementLine.DefaultDimension;

    salesLine.createLine(NoYes::No,
                         NoYes::No,
                         NoYes::No,
                         NoYes::Yes,
                         NoYes::No,
                         NoYes::No
                        );
    if(salesLine.InterCompanyInventTransId && salesLine.InventRefTransId)
    {
        salesLine.InventRefTransId        = '';
        salesLine.InventRefId             = '';
        salesLine.doUpdate();
    }
    if (salesLine.DefaultDimension != _agreementLine.DefaultDimension)
    {
        ttsbegin;
        salesLine.selectForUpdate(true);
        salesLine.DefaultDimension = _agreementLine.DefaultDimension;
        salesLine.doUpdate();
        ttscommit;
    }

    return salesLine;
}

public static PurchTable createPurchTable(PurchAgreementHeader  _purchAgreementHeader,SalesId _salesId)
{
    ETG_PurchaseAgreementHeader     purchAgreementHeaderTrade;
    PurchAgreementHeaderHistory     agreementHeaderHistory;
    PurchTable                      purchTable;
    VendTable                       vendTable;
    NumberSeq                       numberSeq;

    try
    {
        select firstonly ConfirmationNumber,PurchNumberSequence from agreementHeaderHistory
            order by agreementHeaderHistory.ConfirmationNumber desc
                where agreementHeaderHistory.PurchNumberSequence == _purchAgreementHeader.PurchNumberSequence
        join purchAgreementHeaderTrade
            where purchAgreementHeaderTrade.PurchAgreementId == agreementHeaderHistory.PurchNumberSequence;

        purchTable.clear();
        numberSeq = NumberSeq::newGetNum(PurchParameters::numRefPurchId());
        numberSeq.used();
        purchTable.PurchId = numberSeq.num();

        purchTable.initValue();
        vendTable               = VendTable::find(_purchAgreementHeader.VendAccount);
        purchTable.OrderAccount = _purchAgreementHeader.VendAccount;
        purchTable.initFromVendTable(vendTable);
        purchTable.initFromPurchAgreementHeader(_purchAgreementHeader,true,true);
        purchTable.ETG_TPSalesId                    = _salesId;
        purchTable.ETG_IsThirdParty                 = NoYes::Yes;
        purchTable.ETG_AgreementConfirmationVersion = _purchAgreementHeader.PurchNumberSequence + "-" + agreementHeaderHistory.ConfirmationNumber;
        purchTable.DefaultDimension = _purchAgreementHeader.DefaultDimension;

        purchTable.insert();
        info(strFmt('TP purchase order %1 has been created successfully',purchTable.PurchId));
        ETG_ReleaseOrder::createPurchTrade(purchTable.PurchId,purchAgreementHeaderTrade);

        if(purchTable.InterCompanySalesId)
        {
            ETG_ReleaseOrder::intercompanySalesTrade(purchTable);
        }

    }
    catch(Exception::Error)
    {
        ttsabort;
    }

    return purchTable;
}

public static PurchLine createPurchLine(AgreementLineQuantityCommitment _agreementLine,SalesLine _salesLine)
{
    PurchLine               purchLine;    
    PurchTable              purchTable = PurchTable::find(_salesLine.salesTable().ETG_TPPurchId);

    purchLine.PurchId       = purchTable.PurchId;
    purchLine.initFromPurchTable(purchTable);

    purchLine.ItemId            = _agreementLine.ItemId; 
   // purchLine.initFromItemOrCategory( purchLine.ItemId,0,'',false,false);
    purchLine.itemIdChanged();
    purchLine.initFromAgreementLine(_agreementLine);
    purchLine.PurchQty          = _salesLine.SalesQty;       
    purchLine.QtyOrdered        = purchLine.calcQtyOrdered(purchLine.PurchQty);
    purchLine.VariantId         = InventDimCombination::findByInventDim(purchLine.ItemId, purchLine.inventDim()).RetailVariantId;

    purchLine.ETG_TPInventTransId     = _salesLine.InventTransId;      
    if(ETG_Parameters::find().ETGIsAutoMarking)
    {
        purchLine.InventRefTransId        = _salesLine.InventTransId;
        purchLine.InventRefId             = _salesLine.SalesId;
    }

    purchLine.MatchingAgreementLine   = _agreementLine.RecId;
    purchLine.DefaultDimension = _agreementLine.DefaultDimension;
    purchLine.createLine(NoYes::Yes,
                         NoYes::No,
                         NoYes::No,
                         NoYes::Yes,
                         NoYes::No,
                         NoYes::No);

    if(purchLine.InterCompanyInventTransId &&  purchLine.InventRefTransId)
    {
        purchLine.InventRefTransId        = '';
        purchLine.InventRefId             = '';
        purchLine.doUpdate();
    }

    if (purchLine.DefaultDimension != _agreementLine.DefaultDimension)
    {
        ttsbegin;
        purchLine.selectForUpdate(true);
        purchLine.DefaultDimension = _agreementLine.DefaultDimension;
        purchLine.doUpdate();
        ttscommit;
    }

    return purchLine;
}

public static void intercompanySalesTrade(PurchTable _purchTable)
{
    ETG_SalesTableTrade             salesTableTrade;
    ETG_SalesAgreementHeader        salesTradeAgreementHeader;
    AgreementReference              agreementRef;
    SalesAgreementHeader            salesAgreementHeader;

    select firstonly DerivedAgreement from agreementRef
        where agreementRef.SourceAgreement == _purchTable.MatchingAgreement;

    changecompany(_purchTable.InterCompanyCompanyId)
    {
        select firstonly SalesNumberSequence from salesAgreementHeader
            where salesAgreementHeader.RecId == agreementRef.DerivedAgreement
        join salesTradeAgreementHeader
            where salesTradeAgreementHeader.SalesAgreementId == salesAgreementHeader.SalesNumberSequence;

        if(salesTradeAgreementHeader)
        {
            salesTableTrade.SalesId                           = _purchTable.InterCompanySalesId;
            salesTableTrade.AdvanceDue                        = salesTradeAgreementHeader.AdvanceDue;
            salesTableTrade.BuyerAccountNum                   = salesTradeAgreementHeader.BuyerAccountNum;
            salesTableTrade.BuyerDeliveryAddress              = salesTradeAgreementHeader.BuyerDeliveryAddress;
            salesTableTrade.BuyerBank                         = salesTradeAgreementHeader.BuyerBank;
            salesTableTrade.SellerAccountNum                  = salesTradeAgreementHeader.SellerAccountNum;
            salesTableTrade.SellerBank                        = salesTradeAgreementHeader.SellerBank;
            salesTableTrade.SellerDeliveryAddress             = salesTradeAgreementHeader.SellerDeliveryAddress;
            salesTableTrade.Consignee                         = salesTradeAgreementHeader.Consignee;
            salesTableTrade.CustomImport                      = salesTradeAgreementHeader.CustomImport;
            salesTableTrade.DeliveryDescription               = salesTradeAgreementHeader.DeliveryDescription;
            salesTableTrade.FromDatePort                      = salesTradeAgreementHeader.FromDatePort;
            salesTableTrade.Future                            = salesTradeAgreementHeader.Future;
            salesTableTrade.ImportDate                        = salesTradeAgreementHeader.ImportDate;
            salesTableTrade.Notes                             = salesTradeAgreementHeader.Notes;
            salesTableTrade.Notifytodifferentparty            = salesTradeAgreementHeader.Notifytodifferentparty;
            salesTableTrade.Number                            = salesTradeAgreementHeader.Number;
            salesTableTrade.OnAccountOf                       = salesTradeAgreementHeader.OnAccountOf;
            salesTableTrade.PortOfDischarge                   = salesTradeAgreementHeader.PortOfDischarge;
            salesTableTrade.PortOfLoading                     = salesTradeAgreementHeader.PortOfLoading;
            salesTableTrade.PricingFromDate                   = salesTradeAgreementHeader.PricingFromDate;
            salesTableTrade.PricingMonth                      = salesTradeAgreementHeader.PricingMonth;
            salesTableTrade.PricingTodate                     = salesTradeAgreementHeader.PricingTodate;
            salesTableTrade.TermPaymDescription               = salesTradeAgreementHeader.TermPaymDescription;
            salesTableTrade.TermsOfDelDescription             = salesTradeAgreementHeader.TermsOfDelDescription;
            salesTableTrade.Through                           = salesTradeAgreementHeader.Through;
            salesTableTrade.ToDatePort                        = salesTradeAgreementHeader.ToDatePort;
            salesTableTrade.Buyersecondarybank                = salesTradeAgreementHeader.Buyersecondarybank;
            salesTableTrade.Sellersecondarybank               = salesTradeAgreementHeader.Sellersecondarybank;
            salesTableTrade.PortOfDischargeDesc               = salesTradeAgreementHeader.PortOfDischargeDesc;
            salesTableTrade.PortOfLoadingDesc                 = salesTradeAgreementHeader.PortOfLoadingDesc;
            salesTableTrade.Name                              = salesTradeAgreementHeader.Name;
            salesTableTrade.Address                           = salesTradeAgreementHeader.Address;
            salesTableTrade.PackingGroup                      = salesTradeAgreementHeader.PackingGroup;
            salesTableTrade.QuantityConditions                = salesTradeAgreementHeader.QuantityConditions;
            salesTableTrade.ShipperBuyer                      = salesTradeAgreementHeader.ShipperBuyer;
            salesTableTrade.PermitNumber                      = salesTradeAgreementHeader.PermitNumber;
            salesTableTrade.insert();
        }          
    }
}

